'use client';

import { useState } from 'react';
import Link from 'next/link';
import BottomNav from '../components/BottomNav';
import { ArrowLeft, Package, Clock, CheckCircle, Truck } from 'lucide-react';
import '../styles/orders.css';

// Mock data for orders
const mockOrders = [
  {
    id: 'ORD-001',
    date: '2024-11-20',
    status: 'pending',
    items: [
      { id: 1, title: 'Wireless Headphones', quantity: 1, price: 89.99, image: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=100&h=100&fit=crop' },
      { id: 2, title: 'Smart Watch', quantity: 1, price: 199.99, image: 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=100&h=100&fit=crop' }
    ],
    total: 289.98,
    deliveryDate: '2024-11-25'
  },
  {
    id: 'ORD-002',
    date: '2024-11-15',
    status: 'completed',
    items: [
      { id: 3, title: 'Laptop Stand', quantity: 1, price: 49.99, image: 'https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=100&h=100&fit=crop' }
    ],
    total: 49.99,
    deliveryDate: '2024-11-18'
  },
  {
    id: 'ORD-003',
    date: '2024-11-10',
    status: 'completed',
    items: [
      { id: 4, title: 'Gaming Mouse', quantity: 2, price: 29.99, image: 'https://images.unsplash.com/photo-1527814050087-3793815479db?w=100&h=100&fit=crop' },
      { id: 5, title: 'Mechanical Keyboard', quantity: 1, price: 129.99, image: 'https://images.unsplash.com/photo-1587829741301-dc798b83add3?w=100&h=100&fit=crop' }
    ],
    total: 189.97,
    deliveryDate: '2024-11-13'
  }
];

export default function OrdersPage() {
  const [activeTab, setActiveTab] = useState('all');

  const pendingOrders = mockOrders.filter(order => order.status === 'pending');
  const completedOrders = mockOrders.filter(order => order.status === 'completed');

  const getStatusIcon = (status) => {
    switch (status) {
      case 'pending':
        return <Clock size={16} className="status-icon pending" />;
      case 'completed':
        return <CheckCircle size={16} className="status-icon completed" />;
      default:
        return <Package size={16} className="status-icon" />;
    }
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'pending':
        return 'Processing';
      case 'completed':
        return 'Delivered';
      default:
        return status;
    }
  };

  const OrderCard = ({ order }) => (
    <div className="order-card">
      <div className="order-header">
        <div className="order-info">
          <h3 className="order-id">Order #{order.id}</h3>
          <p className="order-date">{new Date(order.date).toLocaleDateString()}</p>
        </div>
        <div className="order-status">
          {getStatusIcon(order.status)}
          <span className={`status-text ${order.status}`}>{getStatusText(order.status)}</span>
        </div>
      </div>

      <div className="order-items">
        {order.items.map((item) => (
          <div key={item.id} className="order-item">
            <img src={item.image} alt={item.title} className="item-image" />
            <div className="item-details">
              <h4 className="item-title">{item.title}</h4>
              <p className="item-quantity">Qty: {item.quantity}</p>
              <p className="item-price">${item.price.toFixed(2)}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="order-footer">
        <div className="order-total">
          <span className="total-label">Total:</span>
          <span className="total-amount">${order.total.toFixed(2)}</span>
        </div>
        {order.status === 'pending' && (
          <div className="delivery-info">
            <Truck size={14} />
            <span>Expected: {new Date(order.deliveryDate).toLocaleDateString()}</span>
          </div>
        )}
      </div>
    </div>
  );

  const renderOrders = (orders, title) => (
    <div className="orders-section">
      <h2 className="section-title">{title} ({orders.length})</h2>
      {orders.length === 0 ? (
        <div className="empty-orders">
          <Package size={48} className="empty-icon" />
          <p>No {title.toLowerCase()} orders</p>
        </div>
      ) : (
        <div className="orders-list">
          {orders.map((order) => (
            <OrderCard key={order.id} order={order} />
          ))}
        </div>
      )}
    </div>
  );

  return (
    <div className="page-content">
      <div className="container" style={{ paddingTop: '20px' }}>
        <div className="orders-header">
          <Link href="/" className="back-link">
            <ArrowLeft size={16} />
            Back to Shopping
          </Link>
          <h1 className="orders-title">My Orders</h1>
        </div>

        <div className="orders-tabs">
          <button
            className={`tab-button ${activeTab === 'all' ? 'active' : ''}`}
            onClick={() => setActiveTab('all')}
          >
            All Orders ({mockOrders.length})
          </button>
          <button
            className={`tab-button ${activeTab === 'pending' ? 'active' : ''}`}
            onClick={() => setActiveTab('pending')}
          >
            Pending ({pendingOrders.length})
          </button>
          <button
            className={`tab-button ${activeTab === 'completed' ? 'active' : ''}`}
            onClick={() => setActiveTab('completed')}
          >
            Completed ({completedOrders.length})
          </button>
        </div>

        {activeTab === 'all' && (
          <>
            {renderOrders(pendingOrders, 'Pending Orders')}
            {renderOrders(completedOrders, 'Completed Orders')}
          </>
        )}

        {activeTab === 'pending' && renderOrders(pendingOrders, 'Pending Orders')}
        {activeTab === 'completed' && renderOrders(completedOrders, 'Completed Orders')}
      </div>
      <BottomNav />
    </div>
  );
}